import { GoogleGenAI, Type, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY || '';

export class GeminiService {
  private static ai = new GoogleGenAI({ apiKey: API_KEY });

  static async checkSymptoms(symptoms: string) {
    const response = await this.ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `User symptoms: ${symptoms}. Provide simple first aid steps, estimated severity (Low/Medium/High), and recommended actions. Keep language simple for rural users.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            advice: { type: Type.STRING },
            severity: { type: Type.STRING },
            steps: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["advice", "severity", "steps"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  }

  static async speakText(text: string) {
    const response = await this.ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say clearly: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      await this.playRawPCM(base64Audio);
    }
  }

  private static async playRawPCM(base64: string) {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const binary = atob(base64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);

    const dataInt16 = new Int16Array(bytes.buffer);
    const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }

    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start();
  }
}

import React from 'react';

interface LayoutProps {
  children: React.ReactNode;
  title: string;
  onBack?: () => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, title, onBack, activeTab, setActiveTab }) => {
  return (
    <div className="flex flex-col min-h-screen pb-20 max-w-md mx-auto bg-white shadow-xl relative">
      <header className="sticky top-0 z-50 bg-red-600 text-white p-4 flex items-center shadow-lg">
        {onBack && (
          <button onClick={onBack} className="mr-3 p-2 hover:bg-red-700 rounded-full transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
        )}
        <h1 className="text-xl font-bold tracking-tight">{title}</h1>
      </header>

      <main className="flex-1 overflow-y-auto p-4">
        {children}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t flex justify-around p-2 z-50 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
        <TabButton icon="🏠" label="Home" active={activeTab === 'home'} onClick={() => setActiveTab('home')} />
        <TabButton icon="📖" label="First Aid" active={activeTab === 'guides'} onClick={() => setActiveTab('guides')} />
        <TabButton icon="🔍" label="Check" active={activeTab === 'checker'} onClick={() => setActiveTab('checker')} />
        <TabButton icon="📍" label="Help" active={activeTab === 'directory'} onClick={() => setActiveTab('directory')} />
        <TabButton icon="👤" label="Me" active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} />
      </nav>
    </div>
  );
};

const TabButton: React.FC<{ icon: string; label: string; active: boolean; onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick} 
    className={`flex flex-col items-center p-2 rounded-xl transition-all duration-200 ${active ? 'text-red-600 scale-110' : 'text-gray-400'}`}
  >
    <span className="text-2xl">{icon}</span>
    <span className="text-[10px] font-semibold uppercase mt-1">{label}</span>
  </button>
);

export default Layout;

import React, { useState } from 'react';

const SOSButton: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [countdown, setCountdown] = useState(5);

  const handleSOS = () => {
    setIsActive(true);
    let count = 5;
    const interval = setInterval(() => {
      count--;
      setCountdown(count);
      if (count === 0) {
        clearInterval(interval);
        triggerAlert();
      }
    }, 1000);
  };

  const triggerAlert = () => {
    // In a real app, this would use SMS/Network APIs
    alert("🚨 EMERGENCY ALERT SENT!\n\nLocation: Latitude: 6.5244, Longitude: 3.3792\nMedical Profile Shared with nearest responder.");
    setIsActive(false);
    setCountdown(5);
  };

  const cancelSOS = () => {
    setIsActive(false);
    setCountdown(5);
  };

  return (
    <>
      <div className="bg-red-50 p-6 rounded-3xl shadow-sm border border-red-100 flex flex-col items-center">
        <button 
          onClick={handleSOS}
          className="w-32 h-32 rounded-full bg-red-600 shadow-[0_0_30px_rgba(220,38,38,0.5)] flex items-center justify-center animate-pulse active:scale-90 transition-transform"
        >
          <span className="text-white text-4xl font-black">SOS</span>
        </button>
        <p className="mt-4 text-red-800 font-bold text-lg">Tap for Emergency</p>
        <p className="text-red-600 text-sm opacity-75">Notifies local responders & family</p>
      </div>

      {isActive && (
        <div className="fixed inset-0 z-[100] bg-red-600 flex flex-col items-center justify-center p-8 text-white text-center">
          <div className="text-6xl mb-8 animate-bounce">🚨</div>
          <h2 className="text-4xl font-black mb-4 uppercase">Sending Emergency Alert</h2>
          <p className="text-xl mb-12 opacity-90">An emergency alert will be sent in</p>
          <div className="text-9xl font-black mb-12">{countdown}</div>
          <button 
            onClick={cancelSOS}
            className="px-12 py-4 bg-white text-red-600 rounded-full font-bold text-xl shadow-2xl hover:bg-gray-100 transition-colors"
          >
            CANCEL ALERT
          </button>
        </div>
      )}
    </>
  );
};

export default SOSButton;

import React, { useState, useEffect } from 'react';
import { UserProfile, UserRole, Language, EmergencyGuide } from './types';
import { EMERGENCY_GUIDES, HEALTH_DIRECTORY, MOCK_BROADCASTS } from './constants';
import Layout from './components/Layout';
import SOSButton from './components/SOSButton';
import AuthScreen from './views/AuthScreen';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [activeTab, setActiveTab] = useState('home');
  const [selectedGuide, setSelectedGuide] = useState<EmergencyGuide | null>(null);
  const [symptomText, setSymptomText] = useState('');
  const [checkerResult, setCheckerResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('user_profile');
    if (saved) setCurrentUser(JSON.parse(saved));
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('user_profile');
    setCurrentUser(null);
  };

  const checkSymptoms = async () => {
    if (!symptomText) return;
    setLoading(true);
    try {
      const result = await GeminiService.checkSymptoms(symptomText);
      setCheckerResult(result);
    } catch (e) {
      alert("Offline or Error. Try basic first aid steps.");
    } finally {
      setLoading(false);
    }
  };

  const speakGuide = (guide: EmergencyGuide) => {
    const text = `${guide.title}. Steps are: ${guide.steps.join('. ')}`;
    GeminiService.speakText(text);
  };

  if (!currentUser) {
    return <AuthScreen onLogin={(user) => {
      setCurrentUser(user);
      localStorage.setItem('user_profile', JSON.stringify(user));
    }} />;
  }

  return (
    <Layout 
      title={activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} 
      activeTab={activeTab} 
      setActiveTab={(tab) => {
        setActiveTab(tab);
        setSelectedGuide(null);
      }}
      onBack={selectedGuide ? () => setSelectedGuide(null) : undefined}
    >
      {/* Home View */}
      {activeTab === 'home' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold">Hello, {currentUser.fullName.split(' ')[0]} 👋</h2>
              <p className="text-gray-500">How can we help today?</p>
            </div>
            <button onClick={() => setActiveTab('profile')} className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center text-red-600 text-xl font-bold">
              {currentUser.fullName.charAt(0)}
            </button>
          </div>

          <SOSButton />

          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => setActiveTab('guides')} className="bg-blue-50 p-6 rounded-3xl border border-blue-100 flex flex-col items-center hover:shadow-md transition-all">
              <span className="text-3xl mb-2">🩹</span>
              <span className="font-bold text-blue-900">First Aid</span>
            </button>
            <button onClick={() => setActiveTab('directory')} className="bg-green-50 p-6 rounded-3xl border border-green-100 flex flex-col items-center hover:shadow-md transition-all">
              <span className="text-3xl mb-2">🏥</span>
              <span className="font-bold text-green-900">Find Clinic</span>
            </button>
          </div>

          <section>
            <h3 className="font-bold text-lg mb-3 flex items-center">
              <span className="mr-2">📢</span> Community Alerts
            </h3>
            <div className="space-y-3">
              {MOCK_BROADCASTS.map(alert => (
                <div key={alert.id} className={`p-4 rounded-2xl border ${alert.priority === 'high' ? 'bg-orange-50 border-orange-200' : 'bg-gray-50 border-gray-200'}`}>
                  <div className="flex justify-between items-start mb-1">
                    <h4 className="font-bold text-sm uppercase text-gray-700">{alert.title}</h4>
                    <span className="text-[10px] text-gray-400">{alert.date}</span>
                  </div>
                  <p className="text-gray-600 text-sm">{alert.content}</p>
                </div>
              ))}
            </div>
          </section>
        </div>
      )}

      {/* First Aid Guides View */}
      {activeTab === 'guides' && (
        <div className="animate-fadeIn">
          {!selectedGuide ? (
            <div className="grid grid-cols-2 gap-4">
              {EMERGENCY_GUIDES.map(guide => (
                <button 
                  key={guide.id}
                  onClick={() => setSelectedGuide(guide)}
                  className="bg-white p-6 rounded-3xl border-2 border-gray-100 shadow-sm flex flex-col items-center hover:border-red-200 transition-all active:scale-95"
                >
                  <span className="text-4xl mb-3">{guide.icon}</span>
                  <span className="font-bold text-gray-800 text-center">{guide.title}</span>
                </button>
              ))}
            </div>
          ) : (
            <div className="space-y-6">
              <img src={selectedGuide.image} className="w-full h-48 object-cover rounded-3xl shadow-md" alt={selectedGuide.title} />
              <div className="flex justify-between items-center">
                <h2 className="text-3xl font-bold text-red-600">{selectedGuide.title}</h2>
                <button 
                  onClick={() => speakGuide(selectedGuide)}
                  className="p-3 bg-red-100 text-red-600 rounded-full hover:bg-red-200 transition-colors"
                >
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.983 5.983 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.983 3.983 0 0013 10a3.983 3.983 0 00-1.172-2.828 1 1 0 010-1.415z" clipRule="evenodd" />
                  </svg>
                </button>
              </div>
              <div className="space-y-4">
                {selectedGuide.steps.map((step, idx) => (
                  <div key={idx} className="flex gap-4 p-4 bg-gray-50 rounded-2xl border border-gray-100">
                    <span className="w-8 h-8 rounded-full bg-red-600 text-white flex items-center justify-center font-bold flex-shrink-0">
                      {idx + 1}
                    </span>
                    <p className="text-gray-700 font-medium leading-relaxed">{step}</p>
                  </div>
                ))}
              </div>
              <button onClick={() => setSelectedGuide(null)} className="w-full py-4 bg-gray-900 text-white rounded-2xl font-bold uppercase tracking-wide">
                I Finished These Steps
              </button>
            </div>
          )}
        </div>
      )}

      {/* Symptom Checker */}
      {activeTab === 'checker' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-purple-50 p-6 rounded-3xl border border-purple-100">
            <h3 className="text-xl font-bold text-purple-900 mb-2">Smart Health Assistant</h3>
            <p className="text-purple-700 text-sm mb-4">Describe how you feel in simple words. For example: "I have a sharp pain in my chest and feel dizzy."</p>

            <textarea 
              value={symptomText}
              onChange={(e) => setSymptomText(e.target.value)}
              placeholder="Type symptoms here..."
              className="w-full h-32 p-4 rounded-2xl border-2 border-purple-200 focus:border-purple-500 outline-none transition-all resize-none mb-4"
            />

            <button 
              onClick={checkSymptoms}
              disabled={loading || !symptomText}
              className={`w-full py-4 rounded-2xl font-bold text-white transition-all ${loading ? 'bg-purple-300' : 'bg-purple-600 hover:bg-purple-700'}`}
            >
              {loading ? 'Thinking...' : 'Check My Health'}
            </button>
          </div>

          {checkerResult && (
            <div className="bg-white p-6 rounded-3xl border shadow-lg animate-slideUp">
              <div className="flex items-center justify-between mb-4">
                <span className={`px-4 py-1 rounded-full text-xs font-bold uppercase ${
                  checkerResult.severity === 'High' ? 'bg-red-100 text-red-600' : 
                  checkerResult.severity === 'Medium' ? 'bg-orange-100 text-orange-600' : 'bg-green-100 text-green-600'
                }`}>
                  Severity: {checkerResult.severity}
                </span>
                <button onClick={() => setCheckerResult(null)} className="text-gray-400">✕</button>
              </div>
              <h4 className="font-bold text-lg mb-2">Advice:</h4>
              <p className="text-gray-600 mb-4 italic">"{checkerResult.advice}"</p>
              <h4 className="font-bold text-lg mb-2">Suggested Actions:</h4>
              <ul className="space-y-2">
                {checkerResult.steps.map((s: string, i: number) => (
                  <li key={i} className="flex items-start gap-2 text-sm text-gray-700">
                    <span className="text-purple-600 mt-1">•</span> {s}
                  </li>
                ))}
              </ul>
              <div className="mt-6 p-3 bg-red-50 text-red-700 text-[10px] rounded-lg">
                ⚠️ This is AI-guided advice and DOES NOT replace professional medical diagnosis. Call emergency help if symptoms are severe.
              </div>
            </div>
          )}
        </div>
      )}

      {/* Directory */}
      {activeTab === 'directory' && (
        <div className="space-y-4 animate-fadeIn">
          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {['All', 'Clinic', 'Hospital', 'Volunteer'].map(cat => (
              <button key={cat} className="px-4 py-2 bg-gray-100 rounded-full text-sm font-bold whitespace-nowrap text-gray-600 active:bg-red-600 active:text-white">
                {cat}
              </button>
            ))}
          </div>

          {HEALTH_DIRECTORY.map((place, i) => (
            <div key={i} className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm flex items-start gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl flex-shrink-0 ${
                place.type === 'Hospital' ? 'bg-red-50 text-red-600' : 
                place.type === 'Clinic' ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'
              }`}>
                {place.type === 'Hospital' ? '🏥' : place.type === 'Clinic' ? '🩺' : '🤝'}
              </div>
              <div className="flex-1">
                <h4 className="font-bold text-gray-800">{place.name}</h4>
                <p className="text-xs text-gray-500 mb-2">{place.address} • {place.distance}</p>
                <div className="flex gap-2">
                  <a href={`tel:${place.phone}`} className="px-4 py-2 bg-red-600 text-white text-xs font-bold rounded-lg flex items-center gap-1 shadow-md active:scale-95 transition-all">
                    <span>📞</span> Call
