                <img src={capturedImage} className="w-full h-full object-cover" />
                <button 
                  onClick={() => setCapturedImage(null)}
                  className="absolute top-2 right-2 bg-red-600 text-white w-8 h-8 rounded-full flex items-center justify-center shadow-lg"
                >
                  ✕
                </button>
              </div>
            )}

            <button 
              onClick={checkSymptoms}
              disabled={loading || (!symptomText && !capturedImage)}
              className={`w-full py-4 rounded-2xl font-bold text-white shadow-lg transition-all ${loading ? 'bg-purple-300' : 'bg-purple-600 hover:bg-purple-700 active:scale-95'}`}
            >
              {loading ? 'Analyzing Input...' : 'Analyze Now'}
            </button>
          </div>

          {checkerResult && (
            <div className="bg-white p-6 rounded-3xl border shadow-xl animate-slideUp">
              <div className="flex items-center justify-between mb-4">
                <span className={`px-4 py-1 rounded-full text-xs font-bold uppercase ${
                  checkerResult.severity === 'High' ? 'bg-red-100 text-red-600' : 
                  checkerResult.severity === 'Medium' ? 'bg-orange-100 text-orange-600' : 'bg-green-100 text-green-600'
                }`}>
                  Severity: {checkerResult.severity}
                </span>
                <button onClick={() => setCheckerResult(null)} className="text-gray-400">✕</button>
              </div>
              <h4 className="font-bold text-lg mb-2">AI Advice:</h4>
              <p className="text-gray-600 mb-4 italic leading-relaxed">"{checkerResult.advice}"</p>
              <h4 className="font-bold text-lg mb-2">First Aid Steps:</h4>
              <ul className="space-y-3">
                {checkerResult.steps.map((s: string, i: number) => (
                  <li key={i} className="flex items-start gap-3 text-sm text-gray-700">
                    <span className="w-5 h-5 rounded-full bg-purple-100 text-purple-600 flex items-center justify-center text-[10px] font-bold flex-shrink-0 mt-0.5">{i+1}</span>
                    <span>{s}</span>
                  </li>
                ))}
              </ul>
              <div className="mt-6 p-4 bg-red-50 text-red-700 text-[10px] rounded-xl border border-red-100 font-medium">
                ⚠️ THIS IS AN AI ESTIMATE. Always seek professional help for serious injuries.
              </div>
            </div>
          )}

          {showCamera && (
            <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-4">
              <div className="relative w-full max-w-md bg-gray-900 rounded-3xl overflow-hidden shadow-2xl">
                <video ref={videoRef} autoPlay playsInline className="w-full h-[70vh] object-cover" />
                <div className="absolute bottom-8 left-0 right-0 flex justify-center items-center gap-12">
                  <button onClick={closeCamera} className="w-14 h-14 bg-white/20 backdrop-blur-md rounded-full text-white flex items-center justify-center text-xl">✕</button>
                  <button onClick={capturePhoto} className="w-20 h-20 bg-white rounded-full border-4 border-gray-300 shadow-xl active:scale-90 transition-transform"></button>
                  <div className="w-14 h-14"></div> {/* Spacer for balance */}
                </div>
              </div>
              <canvas ref={canvasRef} className="hidden" />
              <p className="text-white mt-6 text-sm font-bold opacity-75">Point camera at the injury/incident</p>
            </div>
          )}
        </div>
      )}

      {/* Directory */}
      {activeTab === 'directory' && (
        <div className="space-y-4 animate-fadeIn">
          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {['All', 'Clinic', 'Hospital', 'Volunteer'].map(cat => (
              <button key={cat} className="px-4 py-2 bg-gray-100 rounded-full text-sm font-bold whitespace-nowrap text-gray-600 active:bg-red-600 active:text-white">
                {cat}
              </button>
            ))}
          </div>

          {HEALTH_DIRECTORY.map((place, i) => (
            <div key={i} className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm flex items-start gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl flex-shrink-0 ${
                place.type === 'Hospital' ? 'bg-red-50 text-red-600' : 
                place.type === 'Clinic' ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'
              }`}>
                {place.type === 'Hospital' ? '🏥' : place.type === 'Clinic' ? '🩺' : '🤝'}
              </div>
              <div className="flex-1">
                <h4 className="font-bold text-gray-800">{place.name}</h4>
                <p className="text-xs text-gray-500 mb-2">{place.address} • {place.distance}</p>
                <div className="flex gap-2">
                  <a href={`tel:${place.phone}`} className="px-4 py-2 bg-red-600 text-white text-xs font-bold rounded-lg flex items-center gap-1 shadow-md active:scale-95 transition-all">
                    <span>📞</span> Call
                  </a>
                  <button className="px-4 py-2 bg-gray-100 text-gray-700 text-xs font-bold rounded-lg active:scale-95 transition-all">
                    📍 Directions
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Profile */}
      {activeTab === 'profile' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="text-center p-8 bg-gray-50 rounded-3xl border border-gray-100">
            <div className="w-24 h-24 bg-red-600 text-white text-4xl font-black flex items-center justify-center rounded-full mx-auto mb-4 border-4 border-white shadow-xl">
              {currentUser.fullName.charAt(0)}
            </div>
            <h2 className="text-2xl font-bold">{currentUser.fullName}</h2>
            <p className="text-red-600 font-bold uppercase tracking-wider text-xs">{currentUser.role}</p>
          </div>

          <div className="space-y-4">
            <h3 className="font-bold text-gray-500 text-xs uppercase px-2 tracking-widest">Medical Details</h3>
            <div className="grid grid-cols-2 gap-3">
              <ProfileItem label="Blood" value={currentUser.bloodGroup} />
              <ProfileItem label="Genotype" value={currentUser.genotype} />
              <ProfileItem label="Age" value={currentUser.age.toString()} />
              <ProfileItem label="Gender" value={currentUser.gender} />
            </div>

            <div className="bg-white p-5 rounded-3xl border border-gray-100 space-y-4 shadow-sm">
              <ProfileSection icon="🏠" label="Address" value={currentUser.address} />
              <ProfileSection icon="⚠️" label="Health Challenges" value={currentUser.healthChallenges || 'None'} />
              <ProfileSection icon="📞" label="Emergency Contact" value={currentUser.emergencyContact} />
              {currentUser.role === UserRole.CAREGIVER && (
                <>
                  <ProfileSection icon="🎓" label="Specialty" value={currentUser.medicalSpecialty || 'General'} />
                  <ProfileSection icon="🤝" label="Communication" value={currentUser.patientInteractionMethod || 'Voice call'} />
                </>
              )}
            </div>
          </div>

          <button onClick={handleLogout} className="w-full py-4 bg-gray-100 text-gray-500 rounded-2xl font-bold mt-8 border-2 border-transparent hover:border-gray-200 transition-all">
            Sign Out
          </button>
        </div>
      )}
    </Layout>
  );
};

const ProfileItem: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="bg-white p-4 rounded-2xl border border-gray-100 text-center shadow-sm">
    <p className="text-[10px] text-gray-400 font-bold uppercase">{label}</p>
    <p className="text-lg font-bold text-gray-800">{value}</p>
  </div>
);

const ProfileSection: React.FC<{ icon: string; label: string; value: string }> = ({ icon, label, value }) => (
  <div className="flex items-start gap-4">
    <span className="text-xl mt-1">{icon}</span>
    <div>
      <p className="text-[10px] text-gray-400 font-bold uppercase">{label}</p>
      <p className="text-sm font-semibold text-gray-700">{value}</p>
    </div>
  </div>
);

export default App;

export enum UserRole {
  PATIENT = 'PATIENT',
  CAREGIVER = 'CAREGIVER'
}

export enum Language {
  ENGLISH = 'en',
  HAUSA = 'ha',
  YORUBA = 'yo',
  IGBO = 'ig'
}

export interface UserProfile {
  id: string;
  role: UserRole;
  fullName: string;
  password?: string; // New field for account security
  age: number;
  gender: string;
  genotype: string;
  bloodGroup: string;
  height: string;
  weight: string;
  address: string;
  preferredLanguage: Language;
  healthChallenges: string;
  emergencyContact: string;
  // Caregiver specific
  medicalSpecialty?: string;
  patientInteractionMethod?: string;
  experience?: string;
}

export interface EmergencyGuide {
  id: string;
  title: string;
  icon: string;
  steps: string[];
  image: string;
}

export interface HealthFacility {
  name: string;
  type: 'Hospital' | 'Clinic' | 'Pharmacy' | 'Volunteer';
  distance: string;
  phone: string;
  address: string;
}

export interface Broadcast {
  id: string;
  title: string;
  content: string;
  date: string;
  priority: 'low' | 'high';
}

import React, { useState } from 'react';
import { UserRole, UserProfile, Language } from '../types';

interface AuthScreenProps {
  onLogin: (user: UserProfile) => void;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [role, setRole] = useState<UserRole>(UserRole.PATIENT);
  const [step, setStep] = useState(1);
  const [signInData, setSignInData] = useState({ fullName: '', password: '' });
  const [formData, setFormData] = useState<Partial<UserProfile>>({
    fullName: '',
    password: '',
    age: 25,
    gender: 'Male',
    genotype: 'AA',
    bloodGroup: 'O+',
    height: '',
    weight: '',
    address: '',
    preferredLanguage: Language.ENGLISH,
    healthChallenges: '',
    emergencyContact: '',
    medicalSpecialty: '',
    patientInteractionMethod: '',
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSignInChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setSignInData(prev => ({ ...prev, [name]: value }));
  };

  const handleNext = () => setStep(prev => prev + 1);
  const handleBack = () => setStep(prev => prev - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isSignUp) {
      if (!formData.fullName || !formData.password) {
        alert("Please provide your name and a secure password.");
        return;
      }
      const newUser = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        role,
      } as UserProfile;

      // Save for "authentication" simulation
      localStorage.setItem(`user_${formData.fullName}`, JSON.stringify(newUser));
      onLogin(newUser);
    } else {
      // Check localStorage for simulated login
      const savedUserString = localStorage.getItem(`user_${signInData.fullName}`);
      if (savedUserString) {
        const savedUser = JSON.parse(savedUserString) as UserProfile;
        if (savedUser.password === signInData.password) {
          onLogin(savedUser);
        } else {
          alert("Incorrect password. Please try again.");
        }
      } else {
        // Fallback for first-time or dummy login
        if (signInData.fullName === 'John Doe' && signInData.password === '1234') {
          onLogin({
            id: '1',
            role: UserRole.PATIENT,
            fullName: 'John Doe',
            age: 30,
            gender: 'Male',
            genotype: 'AA',
            bloodGroup: 'O+',
            height: '175cm',
            weight: '70kg',
            address: '123 Village Path, Rural State',
            preferredLanguage: Language.ENGLISH,
            healthChallenges: 'None',
            emergencyContact: '+234 800 000 0000',
          } as UserProfile);
        } else {
          alert("Account not found. Please sign up first.");
        }
      }
    }
  };

  return (
    <div className="min-h-screen bg-red-600 flex flex-col items-center justify-center p-6 text-white max-w-md mx-auto relative overflow-hidden">
      {/* Visual background elements */}
      <div className="absolute -top-20 -right-20 w-64 h-64 bg-red-500 rounded-full opacity-50 blur-3xl"></div>
      <div className="absolute -bottom-20 -left-20 w-64 h-64 bg-white rounded-full opacity-10 blur-3xl"></div>

      <div className="w-full relative z-10 text-center mb-8">
        <div className="w-24 h-24 bg-white rounded-full mx-auto flex items-center justify-center mb-4 shadow-2xl animate-pulse">
          <span className="text-4xl">❤️</span>
        </div>
        <h1 className="text-3xl font-black tracking-tight mb-2">RuralHealth</h1>
        <p className="opacity-80 font-medium">Safe & Smart Help for Communities</p>
      </div>

      <div className="w-full bg-white text-gray-900 rounded-3xl p-8 shadow-2xl relative z-10 animate-slideUp">
        <h2 className="text-2xl font-bold mb-6 text-center">
          {isSignUp ? `Join as ${role === UserRole.PATIENT ? 'Patient' : 'Caregiver'}` : 'Welcome Back'}
        </h2>

        {!isSignUp ? (
          <form onSubmit={handleSubmit} className="space-y-4">
            <Input 
              label="Full Name" 
              name="fullName" 
              value={signInData.fullName} 
              onChange={handleSignInChange} 
              placeholder="Enter your name" 
              required 
            />
            <Input 
              label="Pin/Password" 
              name="password" 
              type="password" 
              value={signInData.password} 
              onChange={handleSignInChange} 
              placeholder="••••" 
              required 
            />
            <button type="submit" className="w-full py-4 bg-red-600 text-white rounded-2xl font-bold shadow-lg hover:bg-red-700 active:scale-95 transition-all mt-4">
              SIGN IN
            </button>
            <p className="text-center text-sm text-gray-500 mt-4">
              Don't have an account?{' '}
              <button type="button" onClick={() => setIsSignUp(true)} className="text-red-600 font-bold">Sign Up</button>
            </p>
          </form>
        ) : (
          <div className="space-y-4">
            {step === 1 && (
              <div className="space-y-6">
                <p className="text-gray-500 text-center font-medium">Choose your role to continue</p>
                <div className="grid grid-cols-2 gap-4">
                  <RoleButton 
                    active={role === UserRole.PATIENT} 
                    onClick={() => setRole(UserRole.PATIENT)}
                    icon="👤"
                    label="Patient"
                  />
                  <RoleButton 
                    active={role === UserRole.CAREGIVER} 
                    onClick={() => setRole(UserRole.CAREGIVER)}
                    icon="🩺"
                    label="Caregiver"
                  />
                </div>
                <div className="space-y-4 mt-6">
                  <Input label="Full Name" name="fullName" value={formData.fullName} onChange={handleInputChange} placeholder="Full Name" required />
                  <Input label="Secure Password" name="password" type="password" value={formData.password} onChange={handleInputChange} placeholder="Create a password" required />
                  <Input label="Address" name="address" value={formData.address} onChange={handleInputChange} placeholder="House Address" />
                </div>
                <button onClick={handleNext} className="w-full py-4 bg-red-600 text-white rounded-2xl font-bold">NEXT</button>
              </div>
            )}

            {step === 2 && (
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-3">
                  <Input label="Age" name="age" type="number" value={formData.age?.toString()} onChange={handleInputChange} />
                  <Select label="Gender" name="gender" value={formData.gender} onChange={handleInputChange} options={['Male', 'Female', 'Other']} />
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <Select label="Genotype" name="genotype" value={formData.genotype} onChange={handleInputChange} options={['AA', 'AS', 'SS', 'AC']} />
                  <Select label="Blood Group" name="bloodGroup" value={formData.bloodGroup} onChange={handleInputChange} options={['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-']} />
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <Input label="Height" name="height" value={formData.height} onChange={handleInputChange} placeholder="e.g. 1.7m" />
                  <Input label="Weight" name="weight" value={formData.weight} onChange={handleInputChange} placeholder="e.g. 65kg" />
                </div>
                <div className="flex gap-4 mt-6">
                  <button onClick={handleBack} className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-2xl font-bold">BACK</button>
                  <button onClick={handleNext} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-bold shadow-lg">NEXT</button>
                </div>
              </div>
            )}

            {step === 3 && (
              <div className="space-y-4">
                <Select label="Language" name="preferredLanguage" value={formData.preferredLanguage} onChange={handleInputChange} options={Object.values(Language)} />
                <Input label="Health Challenges" name="healthChallenges" value={formData.healthChallenges} onChange={handleInputChange} placeholder="Any medical conditions?" />
                <Input label="Emergency Contact" name="emergencyContact" value={formData.emergencyContact} onChange={handleInputChange} placeholder="Phone Number" />

                {role === UserRole.CAREGIVER && (
                  <>
                    <Input label="Medical Specialty" name="medicalSpecialty" value={formData.medicalSpecialty} onChange={handleInputChange} placeholder="e.g. First Aider, Nurse" />
                    <Input label="Contact Method" name="patientInteractionMethod" value={formData.patientInteractionMethod} onChange={handleInputChange} placeholder="How can patients reach you?" />
                  </>
                )}

                <div className="flex gap-4 mt-6">
                  <button onClick={handleBack} className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-2xl font-bold">BACK</button>
                  <button onClick={handleSubmit} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-bold shadow-lg uppercase tracking-wider">Finish</button>
                </div>
              </div>
            )}

            <p className="text-center text-sm text-gray-500 mt-6">
              Already have an account?{' '}
              <button type="button" onClick={() => setIsSignUp(false)} className="text-red-600 font-bold">Log In</button>
            </p>
          </div>
        )}
      </div>

      <p className="mt-8 text-xs opacity-60 font-medium">Designed for Rural Communities © 2024</p>
    </div>
  );
};

const Input: React.FC<any> = ({ label, ...props }) => (
  <div className="space-y-1">
    <label className="text-[10px] font-bold text-gray-400 uppercase ml-1 tracking-widest">{label}</label>
    <input 
      {...props} 
      className="w-full p-3 rounded-xl border border-gray-200 focus:border-red-600 outline-none text-sm transition-all"
    />
  </div>
);

const Select: React.FC<any> = ({ label, options, ...props }) => (
  <div className="space-y-1">
    <label className="text-[10px] font-bold text-gray-400 uppercase ml-1 tracking-widest">{label}</label>
    <select 
      {...props} 
      className="w-full p-3 rounded-xl border border-gray-200 focus:border-red-600 outline-none text-sm bg-white"
    >
      {options.map((opt: string) => (
        <option key={opt} value={opt}>{opt}</option>
      ))}
    </select>
  </div>
);

const RoleButton: React.FC<{ active: boolean; onClick: () => void; icon: string; label: string }> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`p-6 rounded-3xl border-2 flex flex-col items-center gap-2 transition-all duration-300 ${active ? 'border-red-600 bg-red-50 text-red-600' : 'border-gray-100 bg-gray-50 text-gray-400 opacity-60'}`}
  >
    <span className="text-4xl">{icon}</span>
    <span className="font-bold uppercase text-[10px]">{label}</span>
  </button>
);

export default AuthScreen;
